// Configure your API providers and monthly budget thresholds here
const config = {
  openai: {
    enabled: true,
    apiKey: $env.OPENAI_API_KEY,
    monthlyBudget: 50,  // USD
    alertThreshold: 0.8  // alert at 80% of budget
  },
  anthropic: {
    enabled: true,
    apiKey: $env.ANTHROPIC_API_KEY,
    monthlyBudget: 100,  // USD
    alertThreshold: 0.8
  }
};

// Get first day of current month
const now = new Date();
const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
const today = now.toISOString().split('T')[0];

return [{
  json: {
    config,
    period: { start: startOfMonth, end: today },
    timestamp: now.toISOString()
  }
}];

// Merge and normalize usage data from both providers
const config = $('Configure').item.json.config;
const period = $('Configure').item.json.period;

const results = [];

// --- OpenAI ---
try {
  const oaiData = $('OpenAI Usage').item.json;
  const totalCents = oaiData.total_usage || 0; // OpenAI returns cents
  const totalUSD = totalCents / 100;
  const budget = config.openai.monthlyBudget;
  const ratio = totalUSD / budget;
  results.push({
    provider: 'OpenAI',
    spent: totalUSD,
    budget,
    ratio,
    overThreshold: ratio >= config.openai.alertThreshold,
    overBudget: ratio >= 1.0
  });
} catch (e) {
  results.push({ provider: 'OpenAI', error: e.message });
}

// --- Anthropic ---
try {
  const anthData = $('Anthropic Usage').item.json;
  // Anthropic usage endpoint returns aggregated cost in USD
  const totalUSD = anthData.total_cost_usd || 0;
  const budget = config.anthropic.monthlyBudget;
  const ratio = totalUSD / budget;
  results.push({
    provider: 'Anthropic',
    spent: totalUSD,
    budget,
    ratio,
    overThreshold: ratio >= config.anthropic.alertThreshold,
    overBudget: ratio >= 1.0
  });
} catch (e) {
  results.push({ provider: 'Anthropic', error: e.message });
}

const hasAlerts = results.some(r => r.overThreshold || r.overBudget || r.error);

return [{ json: { results, hasAlerts, period } }];

// Format Telegram alert message
const { results, period } = $json;

const lines = [`⚠️ *AI API Cost Alert* — ${period.start} to ${period.end}\n`];

for (const r of results) {
  if (r.error) {
    lines.push(`• *${r.provider}*: error fetching usage — ${r.error}`);
    continue;
  }
  const bar = '█'.repeat(Math.round(r.ratio * 10)) + '░'.repeat(10 - Math.round(Math.min(r.ratio, 1) * 10));
  const icon = r.overBudget ? '🔴' : r.overThreshold ? '🟡' : '🟢';
  const pct = (r.ratio * 100).toFixed(1);
  lines.push(`${icon} *${r.provider}*: $${r.spent.toFixed(2)} / $${r.budget} (${pct}%)\n\`${bar}\``);
}

return [{ json: { message: lines.join('\n') } }];

// Format daily summary (no alerts — all green)
const { results, period } = $json;

const lines = [`✅ *AI API Daily Summary* — ${period.start}\n`];

for (const r of results) {
  if (r.error) continue;
  const pct = (r.ratio * 100).toFixed(1);
  lines.push(`• *${r.provider}*: $${r.spent.toFixed(2)} / $${r.budget} (${pct}% of budget)`);
}

return [{ json: { message: lines.join('\n') } }];
